public(package) fun add_to_whitelist<T>(treasury: &mut Treasury, addr: address) {
    let wl: &mut Table<address, WhitelistEntry> = dynamic_object_field::borrow_mut(
        &mut treasury.id,
        keys::whitelist_key<T>(),
    );
    assert!(!wl.contains(addr), EAlreadyWhitelisted);
    wl.add(addr, WhitelistEntry { can_send: true, can_receive: true });
}

